diff --git a/App/Apps/W1/StatisticalAccounts/app/src/StatAccGenJnlLineExt.TableExt.al b/App/Apps/W1/StatisticalAccounts/app/src/StatAccGenJnlLineExt.TableExt.al
new file mode 100644
index 00000000..938605d7
--- /dev/null
+++ b/App/Apps/W1/StatisticalAccounts/app/src/StatAccGenJnlLineExt.TableExt.al
@@ -0,0 +1,80 @@
+namespace Microsoft.Finance.Analysis.StatisticalAccount;
+
+using Microsoft.Finance.AllocationAccount;
+using Microsoft.Finance.Dimension;
+using Microsoft.Finance.GeneralLedger.Journal;
+
+tableextension 2637 "Stat. Acc. Gen. Journal Line" extends "Gen. Journal Line"
+{
+    [EventSubscriber(ObjectType::Table, Database::"Gen. Journal Line", 'OnAfterValidateEvent', 'Account No.', false, false)]
+    local procedure HandleAccountNoValidate(var Rec: Record "Gen. Journal Line"; var xRec: Record "Gen. Journal Line"; CurrFieldNo: Integer)
+    begin
+        // When account is set (either directly or from allocation account), ensure dimensions are transferred
+        if (Rec."Allocation Account No." <> '') or (Rec."Selected Alloc. Account No." <> '') then
+            EnsureDimensionsFromAllocationAccount(Rec);
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Gen. Journal Line", 'OnAfterModifyEvent', '', false, false)]
+    local procedure HandleGenJnlLineAfterModify(var Rec: Record "Gen. Journal Line"; var xRec: Record "Gen. Journal Line"; RunTrigger: Boolean)
+    begin
+        // Handle dimension transfer when journal line is modified in context of allocation accounts
+        if ((Rec."Allocation Account No." <> '') or (Rec."Selected Alloc. Account No." <> '')) and
+           ((Rec."Account No." <> xRec."Account No.") or (Rec."Dimension Set ID" = 0)) then
+            EnsureDimensionsFromAllocationAccount(Rec);
+    end;
+
+    local procedure EnsureDimensionsFromAllocationAccount(var GenJournalLine: Record "Gen. Journal Line")
+    var
+        AllocationAccount: Record "Allocation Account";
+        AllocAccountDistribution: Record "Alloc. Account Distribution";
+    begin
+        if (GenJournalLine."Allocation Account No." = '') and (GenJournalLine."Selected Alloc. Account No." = '') then
+            exit;
+
+        // Try to get the allocation account
+        if GenJournalLine."Allocation Account No." <> '' then begin
+            if not AllocationAccount.Get(GenJournalLine."Allocation Account No.") then
+                exit;
+        end else begin
+            if not AllocationAccount.Get(GenJournalLine."Selected Alloc. Account No.") then
+                exit;
+        end;
+
+        // Find the related allocation account distribution for this journal line
+        // Based on the destination account number
+        AllocAccountDistribution.SetRange("Allocation Account No.", AllocationAccount."No.");
+        AllocAccountDistribution.SetRange("Destination Account Number", GenJournalLine."Account No.");
+        
+        if AllocAccountDistribution.FindFirst() then
+            TransferDimensionsFromDistribution(GenJournalLine, AllocAccountDistribution);
+    end;
+
+    local procedure TransferDimensionsFromDistribution(var GenJournalLine: Record "Gen. Journal Line"; var AllocAccountDistribution: Record "Alloc. Account Distribution")
+    var
+        DimensionManagement: Codeunit DimensionManagement;
+        DimensionSetIDArr: array[10] of Integer;
+    begin
+        if AllocAccountDistribution."Dimension Set ID" = 0 then
+            exit;
+
+        if GenJournalLine."Dimension Set ID" = AllocAccountDistribution."Dimension Set ID" then
+            exit;
+
+        if GenJournalLine."Dimension Set ID" = 0 then begin
+            GenJournalLine."Dimension Set ID" := AllocAccountDistribution."Dimension Set ID";
+            DimensionManagement.UpdateGlobalDimFromDimSetID(
+                GenJournalLine."Dimension Set ID",
+                GenJournalLine."Shortcut Dimension 1 Code",
+                GenJournalLine."Shortcut Dimension 2 Code");
+            exit;
+        end;
+
+        DimensionSetIDArr[1] := GenJournalLine."Dimension Set ID";
+        DimensionSetIDArr[2] := AllocAccountDistribution."Dimension Set ID";
+        GenJournalLine."Dimension Set ID" :=
+            DimensionManagement.GetCombinedDimensionSetID(
+                DimensionSetIDArr,
+                GenJournalLine."Shortcut Dimension 1 Code",
+                GenJournalLine."Shortcut Dimension 2 Code");
+    end;
+}

